    <div class="sam-hero__overlay"></div>
    <div class="sam-hero__inner">
      <div class="sam-hero__content">
        <!-- TEMPLATE: Customer name -->
        <p class="sam-hero__overline">Yorkshire Water</p>
        <!-- TEMPLATE: Headline outcome — the number that stops the scroll -->
        <h1 class="sam-hero__h1">&pound;9.8M in benefits. 1,300 assets. 70,000 inspections replaced.</h1>
        <!-- TEMPLATE: One-line summary -->
        <p class="sam-hero__lead">How Yorkshire Water deployed SAM4 across their entire pump network to eliminate unplanned failures and replace manual inspections at scale.</p>
        <div class="sam-hero__actions">
          <!-- TEMPLATE: Replace href with case-specific PDF path -->
          <a href="/downloads/yorkshire-water-case-study.pdf" class="sam-btn sam-btn--primary">Download PDF</a>
        </div>
