  </section>


  <!-- ─── 2. HEADLINE OUTCOME ─── -->
  <!-- TEMPLATE: Replace all stats and labels per case -->
  <section class="sam-case-outcome">
    <div class="sam-case-outcome__inner">
      <div class="sam-case-outcome__grid">
        <div class="sam-case-outcome__item">
