          <span class="sam-case-related__card-link">Read case study &rarr;</span>
        </a>
        <a href="/proof/nyrstar" class="sam-case-related__card">
          <span class="sam-case-related__card-industry">Metals &amp; Mining</span>
          <h3 class="sam-case-related__card-title">Nyrstar</h3>
