</main>", "executeCode": true, "codeCss": "/* ── Tokens (extend header/footer tokens) ── */
:root {
  --sam-space-cadet:     #1F1F33;
  --sam-orange:          #FF5429;
  --sam-orange-dark:     #D7411B;
  --sam-orange-deep:     #A33013;
  --sam-blue:            #005CBA;
  --sam-blue-dark:       #004179;
  --sam-blue-light:      #B3DAFF;
  --sam-teal:            #0098AC;
  --sam-teal-dark:       #006C6C;
  --sam-white:           #FFFFFF;
  --sam-seashell:        #F8F5F2;
  --sam-black:           #111111;
  --sam-comet:           #6B6B7F;
  --sam-muted-dark:      #B0B0C8;
  --sam-border-light:    #E8E4E0;
  --sam-dark-elevated:   #2A2A42;
  --sam-font:  'IBM Plex Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  --sam-mono:  'JetBrains Mono', "SFMono-Regular", Consolas, "Liberation Mono", Menlo, Courier, monospace;
  --sp-01: 2px; --sp-02: 4px; --sp-03: 8px; --sp-04: 12px; --sp-05: 16px;
  --sp-06: 24px; --sp-07: 32px; --sp-08: 48px; --sp-09: 64px; --sp-10: 96px;
  --sp-11: 128px; --sp-12: 160px;
  --shadow-sm:  0 1px 3px rgba(31,31,51,0.08);
  --shadow-md:  0 4px 12px rgba(31,31,51,0.10);
  --shadow-cta: 0 4px 16px rgba(255,84,41,0.25);
  --ease: 150ms ease-out;
}

/* ── Reset ── */
.sam-case { overflow-x: hidden; }

/* ── Shared ── */
.overline { font-family: var(--sam-font); font-size: 0.75rem; font-weight: 600; letter-spacing: 0.08em; text-transform: uppercase; margin: 0 0 var(--sp-04) 0; }
.lead { font-family: var(--sam-font); font-size: 1.25rem; line-height: 1.55; margin: 0 0 var(--sp-07) 0; }
.kpi-value { font-family: var(--sam-mono); font-weight: 700; }
.sam-btn { display: inline-flex; align-items: center; justify-content: center; font-family: var(--sam-font); font-size: 1rem; font-weight: 600; text-decoration: none; border-radius: 6px; cursor: pointer; padding: 14px 32px; transition: background var(--ease), box-shadow var(--ease), border-color var(--ease); }
.sam-btn--primary { background: var(--sam-orange); color: var(--sam-white); border: none; }
.sam-btn--primary:hover { background: var(--sam-orange-dark); box-shadow: var(--shadow-cta); }
.sam-btn--outline { background: transparent; color: var(--sam-space-cadet); border: 2px solid var(--sam-space-cadet); }
.sam-btn--outline:hover { background: var(--sam-seashell); }


/* ============================================================
   1. HERO
   ============================================================ */
.sam-hero--case {
  position: relative; min-height: 520px; display: flex; align-items: center;
  background-size: cover; background-position: center; padding: var(--sp-11) var(--sp-06);
}
.sam-hero__overlay {
  position: absolute; inset: 0;
  background: linear-gradient(to right, rgba(31,31,51,0.88) 0%, rgba(31,31,51,0.75) 45%, rgba(31,31,51,0.35) 100%);
  z-index: 1;
}
.sam-hero__inner { position: relative; z-index: 2; max-width: 1120px; width: 100%; margin: 0 auto; }
.sam-hero__content { max-width: 640px; }
.sam-hero__overline { font-family: var(--sam-font); font-size: 0.75rem; font-weight: 600; letter-spacing: 0.08em; text-transform: uppercase; color: var(--sam-orange); margin: 0 0 var(--sp-04) 0; }
.sam-hero__h1 { font-family: var(--sam-font); font-size: 2.75rem; font-weight: 700; line-height: 1.15; color: var(--sam-white); margin: 0 0 var(--sp-06) 0; }
.sam-hero__lead { font-family: var(--sam-font); font-size: 1.125rem; line-height: 1.6; color: var(--sam-muted-dark); margin: 0 0 var(--sp-07) 0; }
.sam-hero__actions { display: flex; gap: var(--sp-05); flex-wrap: wrap; }


/* ============================================================
   2. HEADLINE OUTCOME
   ============================================================ */
.sam-case-outcome { background: var(--sam-white); padding: var(--sp-09) var(--sp-06); border-bottom: 1px solid var(--sam-border-light); }
.sam-case-outcome__inner { max-width: 1120px; margin: 0 auto; }
.sam-case-outcome__grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: var(--sp-07); text-align: center; }
.sam-case-outcome__item { display: flex; flex-direction: column; gap: var(--sp-03); }
.sam-case-outcome__stat { font-size: 2.5rem; color: var(--sam-space-cadet); }
.sam-case-outcome__label { font-family: var(--sam-font); font-size: 0.875rem; color: var(--sam-comet); line-height: 1.4; }


/* ============================================================
   3. CUSTOMER CONTEXT
   ============================================================ */
.sam-case-context { background: var(--sam-seashell); padding: var(--sp-11) var(--sp-06); }
.sam-case-context__inner { max-width: 1120px; margin: 0 auto; }
.sam-case-context .overline { color: var(--sam-space-cadet); }
.sam-case-context h2 { font-family: var(--sam-font); font-size: 2rem; font-weight: 700; line-height: 1.2; color: var(--sam-space-cadet); margin: 0 0 var(--sp-06) 0; }
.sam-case-context__lead { color: var(--sam-black); max-width: 780px; }

.sam-case-context__details { display: grid; grid-template-columns: repeat(2, 1fr); gap: var(--sp-05); }
.sam-case-context__detail {
  display: flex; flex-direction: column; gap: var(--sp-02);
  padding: var(--sp-05) var(--sp-06); background: var(--sam-white);
  border-left: 3px solid var(--sam-teal-dark); border-radius: 4px;
}
.sam-case-context__detail-label {
  font-family: var(--sam-font); font-size: 0.75rem; font-weight: 600;
  letter-spacing: 0.06em; text-transform: uppercase; color: var(--sam-space-cadet);
}
.sam-case-context__detail-value {
  font-family: var(--sam-font); font-size: 0.9375rem; color: var(--sam-black);
}


/* ============================================================
   4. THE CHALLENGE
   ============================================================ */
.sam-case-challenge { background: var(--sam-white); padding: var(--sp-11) var(--sp-06); }
.sam-case-challenge__inner { max-width: 1120px; margin: 0 auto; }
.sam-case-challenge .overline { color: var(--sam-space-cadet); }
.sam-case-challenge h2 { font-family: var(--sam-font); font-size: 2rem; font-weight: 700; line-height: 1.2; color: var(--sam-space-cadet); margin: 0 0 var(--sp-06) 0; }
.sam-case-challenge__lead { color: var(--sam-black); max-width: 780px; }
.sam-case-challenge__body { font-family: var(--sam-font); font-size: 1rem; line-height: 1.7; color: var(--sam-black); max-width: 780px; margin: 0; }


/* ============================================================
   5. THE SOLUTION
   ============================================================ */
.sam-case-solution { background: var(--sam-seashell); padding: var(--sp-11) var(--sp-06); }
.sam-case-solution__inner { max-width: 1120px; margin: 0 auto; }
.sam-case-solution .overline { color: var(--sam-space-cadet); }
.sam-case-solution h2 { font-family: var(--sam-font); font-size: 2rem; font-weight: 700; line-height: 1.2; color: var(--sam-space-cadet); margin: 0 0 var(--sp-06) 0; }
.sam-case-solution__lead { color: var(--sam-black); max-width: 780px; }

.sam-case-solution__items { display: flex; flex-direction: column; gap: var(--sp-06); }
.sam-case-solution__item {
  border-left: 4px solid var(--sam-teal-dark);
  padding-left: var(--sp-06); padding-top: var(--sp-03); padding-bottom: var(--sp-03);
}
.sam-case-solution__item-title { font-family: var(--sam-font); font-size: 1.125rem; font-weight: 600; color: var(--sam-space-cadet); margin: 0 0 var(--sp-03) 0; }
.sam-case-solution__item-desc { font-family: var(--sam-font); font-size: 0.9375rem; line-height: 1.6; color: var(--sam-black); margin: 0; max-width: 720px; }


/* ============================================================
   6. RESULTS
   ============================================================ */
.sam-case-results { background: var(--sam-white); padding: var(--sp-11) var(--sp-06); }
.sam-case-results__inner { max-width: 1120px; margin: 0 auto; }
.sam-case-results .overline { color: var(--sam-space-cadet); }
.sam-case-results h2 { font-family: var(--sam-font); font-size: 2rem; font-weight: 700; line-height: 1.2; color: var(--sam-space-cadet); margin: 0 0 var(--sp-08) 0; }

.sam-case-results__grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: var(--sp-07); }
.sam-case-results__card {
  background: var(--sam-seashell); border-top: 4px solid var(--sam-orange-dark);
  border-radius: 8px; padding: var(--sp-07) var(--sp-06);
}
.sam-case-results__card-value {
  display: block; font-size: 2rem; color: var(--sam-space-cadet); margin-bottom: var(--sp-04);
}
.sam-case-results__card-title { font-family: var(--sam-font); font-size: 1.0625rem; font-weight: 600; color: var(--sam-space-cadet); margin: 0 0 var(--sp-03) 0; }
.sam-case-results__card-desc { font-family: var(--sam-font); font-size: 0.9375rem; line-height: 1.6; color: var(--sam-black); margin: 0; }


/* ============================================================
   7. CUSTOMER QUOTE
   ============================================================ */
.sam-case-quote { background: var(--sam-seashell); padding: var(--sp-11) var(--sp-06); }
.sam-case-quote__inner { max-width: 800px; margin: 0 auto; text-align: center; }
.sam-case-quote__blockquote { margin: 0; padding: 0; }
.sam-case-quote__text {
  font-family: var(--sam-font); font-size: 1.5rem; font-weight: 400;
  line-height: 1.5; color: var(--sam-space-cadet); font-style: italic;
  margin: 0 0 var(--sp-06) 0;
}
.sam-case-quote__attribution {
  display: flex; flex-direction: column; gap: var(--sp-02);
}
.sam-case-quote__name {
  font-family: var(--sam-font); font-size: 1rem; font-weight: 600; color: var(--sam-space-cadet);
}
.sam-case-quote__company {
  font-family: var(--sam-font); font-size: 0.875rem; color: var(--sam-space-cadet);
}


/* ============================================================
   8. PDF DOWNLOAD + CTA
   ============================================================ */
.sam-case-cta { background: var(--sam-white); padding: var(--sp-11) var(--sp-06); text-align: center; }
.sam-case-cta__inner { max-width: 720px; margin: 0 auto; }
.sam-case-cta h2 { font-family: var(--sam-font); font-size: 2rem; font-weight: 700; line-height: 1.2; color: var(--sam-space-cadet); margin: 0 0 var(--sp-06) 0; }
.sam-case-cta__lead { color: var(--sam-black); margin-bottom: var(--sp-08); }
.sam-case-cta__actions { display: flex; align-items: center; justify-content: center; gap: var(--sp-05); flex-wrap: wrap; }


/* ============================================================
   9. RELATED CASE STUDIES
   ============================================================ */
.sam-case-related { background: var(--sam-seashell); padding: var(--sp-11) var(--sp-06); }
.sam-case-related__inner { max-width: 1120px; margin: 0 auto; }
.sam-case-related .overline { color: var(--sam-space-cadet); }
.sam-case-related h2 { font-family: var(--sam-font); font-size: 2rem; font-weight: 700; line-height: 1.2; color: var(--sam-space-cadet); margin: 0 0 var(--sp-08) 0; }

.sam-case-related__grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: var(--sp-07); }
.sam-case-related__card {
  display: flex; flex-direction: column; gap: var(--sp-04);
  background: var(--sam-white); border-radius: 8px;
  padding: var(--sp-07) var(--sp-06);
  text-decoration: none; color: inherit;
  border: 1px solid var(--sam-border-light);
  transition: box-shadow var(--ease), border-color var(--ease);
}
.sam-case-related__card:hover {
  box-shadow: var(--shadow-md); border-color: var(--sam-space-cadet);
}
.sam-case-related__card-industry {
  font-family: var(--sam-font); font-size: 0.75rem; font-weight: 600;
  letter-spacing: 0.06em; text-transform: uppercase; color: var(--sam-teal-dark);
}
.sam-case-related__card-title {
  font-family: var(--sam-font); font-size: 1.25rem; font-weight: 700;
  color: var(--sam-space-cadet); margin: 0;
}
.sam-case-related__card-outcome {
  font-size: 0.9375rem; color: var(--sam-space-cadet); margin: 0;
}
.sam-case-related__card-link {
  font-family: var(--sam-font); font-size: 0.9375rem; font-weight: 600;
  color: var(--sam-orange-dark); margin-top: auto;
}


/* ============================================================
   RESPONSIVE
   ============================================================ */
@media (max-width: 1055px) {
  .sam-hero--case { min-height: 440px; padding: var(--sp-10) var(--sp-06); }
  .sam-hero__h1 { font-size: 2.25rem; }

  .sam-case-outcome { padding: var(--sp-08) var(--sp-06); }
  .sam-case-outcome__grid { grid-template-columns: repeat(2, 1fr); }

